-- Soak test database: 120 tables across 6 domains (20 per domain).
--
-- Each domain uses a schema that reflects realistic data types for that
-- domain so the CDC pipeline sees a wide variety of MySQL types:
--   INT, SMALLINT, TINYINT, INT UNSIGNED, FLOAT, DECIMAL, CHAR, VARCHAR,
--   TEXT, BOOLEAN, DATE, DATETIME, TIMESTAMP, JSON
--
-- The four columns the writer tasks use (tag, data, value, status) are
-- present in every table with DEFAULT values; all extra columns also have
-- defaults so INSERT (tag, data, value, status) still works without change.
--
-- Domains: customer, order, product, inventory, payment, event

CREATE DATABASE IF NOT EXISTS orders;
USE orders;

-- ── customer domain ─── identity / profile ────────────────────────────────────
-- Extra types: VARCHAR(255), BOOLEAN, INT, FLOAT, JSON, DATE, DATETIME

CREATE TABLE IF NOT EXISTS soak_customer_01 (id INT AUTO_INCREMENT PRIMARY KEY, tag VARCHAR(100) NOT NULL DEFAULT '', data TEXT, value DECIMAL(10,4) DEFAULT 0.0000, status TINYINT DEFAULT 0, name VARCHAR(255) DEFAULT '', email VARCHAR(255) DEFAULT '', phone VARCHAR(32) DEFAULT '', active BOOLEAN DEFAULT TRUE, loyalty_points INT DEFAULT 0, credit_score FLOAT DEFAULT 0.0, preferences JSON DEFAULT NULL, dob DATE DEFAULT NULL, last_login DATETIME DEFAULT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX (tag), INDEX (email));
CREATE TABLE IF NOT EXISTS soak_customer_02 (id INT AUTO_INCREMENT PRIMARY KEY, tag VARCHAR(100) NOT NULL DEFAULT '', data TEXT, value DECIMAL(10,4) DEFAULT 0.0000, status TINYINT DEFAULT 0, name VARCHAR(255) DEFAULT '', email VARCHAR(255) DEFAULT '', phone VARCHAR(32) DEFAULT '', active BOOLEAN DEFAULT TRUE, loyalty_points INT DEFAULT 0, credit_score FLOAT DEFAULT 0.0, preferences JSON DEFAULT NULL, dob DATE DEFAULT NULL, last_login DATETIME DEFAULT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX (tag), INDEX (email));
